function ModuleBtn({ label, active, onClick }) {
  return (
    <button onClick={onClick} style={{ fontFamily: "'Syne', sans-serif", background: active ? "#16a34a" : "transparent", color: active ? "#fff" : "#374151", border: active ? "2px solid #16a34a" : "2px solid #e5e7eb", borderRadius: "12px", padding: "10px 22px", fontWeight: 700, fontSize: 15, cursor: "pointer", transition: "all 0.2s" }}>
      {label}
    </button>
  );
}

function OffreCard({ offre, selected, onSelect }) {
  return (
    <div onClick={() => onSelect(offre.id)} style={{ border: selected ? "2px solid #16a34a" : "2px solid #e5e7eb", borderRadius: "14px", padding: "14px", cursor: "pointer", background: selected ? "#f0fdf4" : "#fff", transition: "all 0.2s" }}>
      {offre.badge && <div style={{ marginBottom: 6 }}><span style={{ fontSize: 11, fontWeight: 700, background: "#fef3c7", color: "#92400e", padding: "2px 8px", borderRadius: 20 }}>{offre.badge}</span></div>}
      <div style={{ fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: 15, color: "#111827" }}>{offre.nom}</div>
      <div style={{ fontFamily: "'DM Sans', sans-serif", color: "#16a34a", fontWeight: 700, fontSize: 13, marginTop: 4 }}>
        {offre.prix_mensuel ? `${offre.prix_mensuel}€/mois HT` : offre.prix_unique ? `${offre.prix_unique}€ licence` : "Sur devis"}
      </div>
    </div>
  );
}

